pub(crate) fn agent_lane_dispatch_result(
    mut activation_view: serde_json::Value,
    dispatch_packet_path: &str,
    preferred_backend: Option<&str>,
    role_selection: &RuntimeConsumptionLaneSelection,
    receipt: &crate::state_store::RunGraphDispatchReceipt,
    host_runtime: serde_json::Value,
) -> serde_json::Value {
    let project_root = std::env::current_dir().unwrap_or_else(|_| PathBuf::from("."));
    let lane_dispatch = crate::runtime_dispatch_state::runtime_agent_lane_dispatch_for_root(
        &project_root,
        dispatch_packet_path,
        preferred_backend,
    );
    let effective_execution_posture =
        crate::runtime_dispatch_state::effective_execution_posture_summary(
            &role_selection.execution_plan,
            &receipt.dispatch_target,
            receipt.selected_backend.as_deref(),
            receipt.activation_agent_type.as_deref(),
            Some(&host_runtime),
            false,
        );
    let execution_truth = summarize_execution_truth_for_route(
        &role_selection.execution_plan,
        crate::runtime_dispatch_state::execution_plan_route_for_dispatch_target(
            &role_selection.execution_plan,
            &receipt.dispatch_target,
        ),
        host_runtime["selected_cli_execution_class"].as_str(),
        receipt.selected_backend.as_deref(),
        Some("activation_view"),
        Some("missing"),
    );
    let body = activation_view
        .as_object_mut()
        .expect("agent-init activation view should serialize to an object");
    body.insert(
        "surface".to_string(),
        serde_json::json!(lane_dispatch.surface),
    );
    body.insert("status".to_string(), serde_json::json!("blocked"));
    body.insert("execution_state".to_string(), serde_json::json!("blocked"));
    body.insert(
        "activation_command".to_string(),
        serde_json::json!(lane_dispatch.activation_command),
    );
    body.insert(
        "dispatch_packet_path".to_string(),
        serde_json::json!(dispatch_packet_path),
    );
    body.insert("host_runtime".to_string(), host_runtime);
    body.insert(
        "effective_execution_posture".to_string(),
        effective_execution_posture,
    );
    body.insert("execution_truth".to_string(), execution_truth);
    body.insert(
        "blocker_code".to_string(),
        serde_json::json!("internal_activation_view_only"),
    );
    body.insert(
        "blocker_reason".to_string(),
        serde_json::json!(
            "selected host/backend returned only an activation view without execution evidence"
        ),
    );
    body.insert(
        "backend_dispatch".to_string(),
        lane_dispatch.backend_dispatch,
    );
    body.insert(
        "role_selection".to_string(),
        serde_json::to_value(role_selection).expect("lane selection should serialize"),
    );
    activation_view
}

fn refresh_execution_truth(
    body: &mut serde_json::Map<String, serde_json::Value>,
    role_selection: &RuntimeConsumptionLaneSelection,
    receipt: &crate::state_store::RunGraphDispatchReceipt,
    effective_selected_backend: Option<&str>,
    execution_evidence_status: &str,
) {
    let host_runtime = body
        .get("host_runtime")
        .cloned()
        .unwrap_or(serde_json::Value::Null);
    let activation_kind = body
        .get("activation_semantics")
        .and_then(|value| value.get("activation_kind"))
        .and_then(serde_json::Value::as_str)
        .unwrap_or("unknown");
    body.insert(
        "execution_truth".to_string(),
        summarize_execution_truth_for_route(
            &role_selection.execution_plan,
            crate::runtime_dispatch_state::execution_plan_route_for_dispatch_target(
                &role_selection.execution_plan,
                &receipt.dispatch_target,
            ),
            host_runtime["selected_cli_execution_class"].as_str(),
            effective_selected_backend,
            Some(activation_kind),
            Some(execution_evidence_status),
        ),
    );
}

fn mark_dispatch_result_execution_evidence(
    body: &mut serde_json::Map<String, serde_json::Value>,
    evidence_kind: &str,
    backend_id: &str,
) {
    let activation_semantics = body
        .entry("activation_semantics".to_string())
        .or_insert_with(|| serde_json::json!({}));
    let activation_semantics = activation_semantics
        .as_object_mut()
        .expect("activation_semantics should serialize to an object");
    activation_semantics.insert(
        "activation_kind".to_string(),
        serde_json::json!("execution_evidence"),
    );
    activation_semantics.insert("view_only".to_string(), serde_json::json!(false));
    activation_semantics.insert("executes_packet".to_string(), serde_json::json!(true));
    activation_semantics.insert(
        "records_completion_receipt".to_string(),
        serde_json::json!(true),
    );
    activation_semantics.insert(
        "transfers_root_session_write_authority".to_string(),
        serde_json::json!(false),
    );
    activation_semantics.insert(
        "root_session_write_guard_remains_authoritative".to_string(),
        serde_json::json!(true),
    );
    activation_semantics.insert(
        "next_lawful_action".to_string(),
        serde_json::json!(
            "treat this result as receipt-backed delegated-lane execution evidence and continue through runtime downstream progression"
        ),
    );
    body.insert(
        "execution_evidence".to_string(),
        serde_json::json!({
            "status": "recorded",
            "evidence_kind": evidence_kind,
            "backend_id": backend_id,
            "receipt_backed": true,
            "records_dispatch_result": true,
        }),
    );
    if let Some(posture) = body
        .get_mut("effective_execution_posture")
        .and_then(serde_json::Value::as_object_mut)
    {
        posture.insert(
            "activation_evidence_state".to_string(),
            serde_json::json!("execution_evidence"),
        );
        posture.insert(
            "receipt_backed_execution_evidence".to_string(),
            serde_json::json!(true),
        );
        posture.insert(
            "selected_backend".to_string(),
            serde_json::json!(backend_id),
        );
    }
    if let Some(posture) = body
        .get_mut("execution_truth")
        .and_then(serde_json::Value::as_object_mut)
    {
        posture.insert(
            "effective_selected_backend".to_string(),
            serde_json::json!(backend_id),
        );
        if let Some(activation_evidence) = posture
            .get_mut("activation_evidence")
            .and_then(serde_json::Value::as_object_mut)
        {
            activation_evidence.insert(
                "activation_kind".to_string(),
                serde_json::json!("execution_evidence"),
            );
            activation_evidence.insert(
                "execution_evidence_status".to_string(),
                serde_json::json!("recorded"),
            );
            activation_evidence.insert("receipt_backed".to_string(), serde_json::json!(true));
        }
    }
}

pub(crate) async fn execute_internal_agent_lane_dispatch(
    state_root: &Path,
    project_root: &Path,
    dispatch_packet_path: &str,
    preferred_backend: Option<&str>,
    role_selection: &RuntimeConsumptionLaneSelection,
    receipt: &crate::state_store::RunGraphDispatchReceipt,
    host_runtime: serde_json::Value,
) -> Result<Option<serde_json::Value>, String> {
    let overlay = crate::runtime_dispatch_state::load_project_overlay_yaml_for_root(project_root)?;
    let (selected_cli_system, selected_cli_entry) =
        crate::runtime_dispatch_state::selected_host_cli_system_for_runtime_dispatch(&overlay);
    let execution_class = selected_cli_entry
        .as_ref()
        .and_then(|entry| yaml_lookup(entry, &["execution_class"]))
        .and_then(serde_yaml::Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| {
            host_runtime["selected_cli_execution_class"]
                .as_str()
                .unwrap_or("unknown")
        });
    if selected_cli_system != "codex" || execution_class != "internal" {
        return Ok(None);
    }

    let Some(carrier) = selected_internal_codex_carrier(
        selected_cli_entry.as_ref(),
        preferred_backend,
        receipt,
        role_selection,
    ) else {
        return Ok(None);
    };

    let carrier_id = carrier["role_id"].as_str().unwrap_or("codex");
    let (command, args) =
        configured_internal_codex_activation_parts(project_root, dispatch_packet_path, &carrier)?;
    let wall_timeout_seconds = Some(configured_internal_codex_dispatch_wall_timeout_seconds(
        selected_cli_entry.as_ref(),
    ));
    let (effective_command, effective_args) =
        wrap_command_with_optional_timeout(command.clone(), args.clone(), wall_timeout_seconds);
    let activation_command =
        crate::runtime_dispatch_state::render_command_display(&effective_command, &effective_args);
    let runtime_env = configured_internal_codex_runtime_env(project_root, carrier_id)?;

    let mut process = std::process::Command::new(&effective_command);

fn backend_execution_dimension(backend_class: &str) -> &'static str {
    match backend_class.trim() {
        "external_cli" | "external" => "external",
        "internal" | "internal_cli" => "internal",
        "taskflow_pack" => "taskflow_pack",
        _ => "unknown",
    }
}

pub(crate) fn effective_execution_posture_summary(
    execution_plan: &serde_json::Value,
    dispatch_target: &str,
    selected_backend: Option<&str>,
    activation_agent_type: Option<&str>,
    host_runtime: Option<&serde_json::Value>,
    receipt_backed_execution_evidence: bool,
) -> serde_json::Value {
    let route = execution_plan_route_for_dispatch_target(execution_plan, dispatch_target);
    let route_primary_backend =
        route.and_then(|lane| selected_backend_from_execution_plan_route(execution_plan, lane));
    let fallback_backend = route.and_then(fallback_executor_backend_from_route);
    let fanout_backends = route
        .map(fanout_executor_backends_from_route)
        .unwrap_or_default();
    let effective_selected_backend = selected_backend
        .filter(|value| !value.trim().is_empty())
        .map(str::to_string)
        .or_else(|| {
            activation_agent_type
                .filter(|value| !value.trim().is_empty())
                .map(str::to_string)
        })
        .or_else(|| route_primary_backend.clone());
    let selected_backend_source = if selected_backend.is_some_and(|value| !value.trim().is_empty())
    {
        "dispatch_receipt"
    } else if activation_agent_type.is_some_and(|value| !value.trim().is_empty()) {
        "activation_agent_type"
    } else if route_primary_backend.is_some() {
        "route_primary_backend"
    } else {
        "unknown"
    };
    let selected_backend_class = effective_selected_backend
        .as_deref()
        .map(|backend_id| backend_class_for_execution_plan_backend(execution_plan, backend_id));
    let route_primary_backend_class = route_primary_backend
        .as_deref()
        .map(|backend_id| backend_class_for_execution_plan_backend(execution_plan, backend_id));
    let fallback_backend_class = fallback_backend
        .as_deref()
        .map(|backend_id| backend_class_for_execution_plan_backend(execution_plan, backend_id));
    let fanout_backend_classes = fanout_backends
        .iter()
        .map(|backend_id| {
            (
                backend_id.clone(),
                serde_json::Value::String(backend_class_for_execution_plan_backend(
                    execution_plan,
                    backend_id,
                )),
            )
        })
        .collect::<serde_json::Map<String, serde_json::Value>>();

    let route_dimensions = route_primary_backend_class
        .iter()
        .chain(fallback_backend_class.iter())
        .map(|value| backend_execution_dimension(value))
        .chain(
            fanout_backend_classes
                .values()
                .filter_map(serde_json::Value::as_str)
                .map(backend_execution_dimension),
        )
        .collect::<std::collections::BTreeSet<_>>();
    let route_contains_internal_backend = route_dimensions.contains("internal");
    let route_contains_external_backend = route_dimensions.contains("external");
    let mixed_route_backends = route_contains_internal_backend && route_contains_external_backend;

    let selected_execution_class = host_runtime
        .and_then(|value| value.get("selected_cli_execution_class"))
        .cloned()
        .unwrap_or(serde_json::Value::Null);
    let selected_cli_system = host_runtime
        .and_then(|value| value.get("selected_cli_system"))
        .cloned()
        .unwrap_or(serde_json::Value::Null);
    let host_execution_dimension = selected_execution_class
        .as_str()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("unknown");
    let selected_backend_dimension = selected_backend_class
        .as_deref()
        .map(backend_execution_dimension)
        .unwrap_or("unknown");
    let hybrid_host_backend_selection = matches!(
        (host_execution_dimension, selected_backend_dimension),
        ("internal", "external") | ("external", "internal")
    );
    let effective_posture_kind = if hybrid_host_backend_selection || mixed_route_backends {
        "mixed"
    } else if selected_backend_dimension == "external" || host_execution_dimension == "external" {
        "external"
    } else if selected_backend_dimension == "internal" || host_execution_dimension == "internal" {
        "internal"
    } else if selected_backend_dimension == "taskflow_pack" {
        "taskflow_pack"
    } else {
        "unknown"
    };

    serde_json::json!({
        "dispatch_target": dispatch_target,
        "selected_cli_system": selected_cli_system,
        "selected_execution_class": selected_execution_class,
        "selected_backend": effective_selected_backend,
        "selected_backend_source": selected_backend_source,
        "selected_backend_class": selected_backend_class,
        "route_primary_backend": route_primary_backend,
        "route_primary_backend_class": route_primary_backend_class,
        "fallback_backend": fallback_backend,
        "fallback_backend_class": fallback_backend_class,
        "fanout_backends": fanout_backends,
        "fanout_backend_classes": fanout_backend_classes,
        "route_contains_internal_backend": route_contains_internal_backend,
        "route_contains_external_backend": route_contains_external_backend,
        "mixed_route_backends": mixed_route_backends,
        "hybrid_host_backend_selection": hybrid_host_backend_selection,
        "effective_posture_kind": effective_posture_kind,
        "activation_evidence_state": if receipt_backed_execution_evidence {
            "execution_evidence"
        } else {
            "activation_view_only"
        },
        "receipt_backed_execution_evidence": receipt_backed_execution_evidence,
    })
}

